const input = $input.first().json;
const action = input.action || 'get_weather';

const WMO = { 0: 'clear sky', 1: 'mainly clear', 2: 'partly cloudy', 3: 'overcast', 45: 'fog', 48: 'depositing rime fog', 51: 'light drizzle', 53: 'moderate drizzle', 55: 'dense drizzle', 56: 'light freezing drizzle', 57: 'dense freezing drizzle', 61: 'slight rain', 63: 'moderate rain', 65: 'heavy rain', 66: 'light freezing rain', 67: 'heavy freezing rain', 71: 'slight snowfall', 73: 'moderate snowfall', 75: 'heavy snowfall', 77: 'snow grains', 80: 'slight rain showers', 81: 'moderate rain showers', 82: 'violent rain showers', 85: 'slight snow showers', 86: 'heavy snow showers', 95: 'thunderstorm', 96: 'thunderstorm with slight hail', 99: 'thunderstorm with heavy hail' };

const MA_FEEDS = { AT: 'austria', BE: 'belgium', BA: 'bosnia-herzegovina', BG: 'bulgaria', HR: 'croatia', CY: 'cyprus', CZ: 'czechia', DK: 'denmark', EE: 'estonia', FI: 'finland', FR: 'france', GR: 'greece', HU: 'hungary', IS: 'iceland', IE: 'ireland', IL: 'israel', IT: 'italy', LV: 'latvia', LT: 'lithuania', LU: 'luxembourg', MT: 'malta', MD: 'moldova', ME: 'montenegro', NL: 'netherlands', MK: 'republic-of-north-macedonia', NO: 'norway', PL: 'poland', PT: 'portugal', RO: 'romania', RS: 'serbia', SK: 'slovakia', SI: 'slovenia', ES: 'spain', SE: 'sweden', UA: 'ukraine', GB: 'united-kingdom' };

const SEV_ORDER = { extreme: 0, severe: 1, moderate: 2, minor: 3 };

function wmoText(code) {
  if (code === null || code === undefined) return 'n/a';
  return WMO[code] || ('weather code ' + code);
}

function num(v, unit) {
  return (v === null || v === undefined) ? 'n/a' : (v + (unit || ''));
}

function tfmt(s) {
  return String(s || '').replace('T', ' ').substring(0, 16);
}

function norm(s) {
  return String(s || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
}

function notExpired(expires) {
  if (!expires) return true;
  const t = Date.parse(expires);
  return isNaN(t) ? true : t > Date.now();
}

function areaCandidates(rawCity, g) {
  const cands = [];
  for (const s of [rawCity, g.name]) { const n = norm(s); if (n.length >= 2 && cands.indexOf(n) === -1) cands.push(n); }
  for (const s of [g.admin2, g.admin1]) { const n = norm(s); if (n.length > 3 && cands.indexOf(n) === -1) cands.push(n); }
  return cands;
}

function fail(msg) {
  return [{ json: { error: msg } }];
}

function out(text) {
  if (text.length > 5000) text = text.substring(0, 5000) + '\n... (truncated)';
  return [{ json: { result: text } }];
}

async function geocode(city) {
  let results = [];
  try {
    const base = 'https://geocoding-api.open-meteo.com/v1/search?name=' + encodeURIComponent(city) + '&count=5&language=';
    const both = await Promise.all([
      helpers.httpRequest({ method: 'GET', url: base + 'en', timeout: 15000 }),
      helpers.httpRequest({ method: 'GET', url: base + 'de', timeout: 15000 })
    ]);
    for (const geo of both) { if (geo.results) results = results.concat(geo.results); }
  } catch (e) {
    throw new Error('Geocoding request failed: ' + e.message);
  }
  if (results.length === 0) {
    throw new Error('City not found: "' + city + '". Check the spelling or try a larger nearby city.');
  }
  let r = results[0];
  for (const cand of results) {
    if ((cand.population || 0) > (r.population || 0)) r = cand;
  }
  return { lat: r.latitude, lon: r.longitude, name: r.name, country: r.country || '', cc: (r.country_code || '').toUpperCase(), admin1: r.admin1 || '', admin2: r.admin2 || '' };
}

function placeLabel(g) {
  return g.name + (g.country ? ', ' + g.country : '');
}

try {
  if (action === 'get_weather') {
    if (!input.city) return fail('Parameter "city" is required (e.g. "Berlin", "New York").');
    const g = await geocode(input.city);
    let days = parseInt(input.days) || 3;
    days = Math.min(Math.max(days, 1), 16);
    const w = await helpers.httpRequest({
      method: 'GET', timeout: 20000,
      url: 'https://api.open-meteo.com/v1/forecast?latitude=' + g.lat + '&longitude=' + g.lon
        + '&current=temperature_2m,apparent_temperature,relative_humidity_2m,precipitation,weather_code,wind_speed_10m,wind_gusts_10m,cloud_cover,pressure_msl'
        + '&daily=weather_code,temperature_2m_max,temperature_2m_min,precipitation_sum,precipitation_probability_max,wind_speed_10m_max,wind_gusts_10m_max,uv_index_max,sunrise,sunset,snowfall_sum'
        + '&timezone=auto&forecast_days=' + days
    });
    const c = w.current || {};
    let r = 'Weather for ' + placeLabel(g) + '\n';
    r += 'Now: ' + num(c.temperature_2m, '°C') + ' (feels like ' + num(c.apparent_temperature, '°C') + '), ' + wmoText(c.weather_code)
      + ', humidity ' + num(c.relative_humidity_2m, '%') + ', wind ' + num(c.wind_speed_10m, ' km/h') + ' (gusts ' + num(c.wind_gusts_10m, ' km/h') + ')'
      + ', clouds ' + num(c.cloud_cover, '%') + ', pressure ' + num(c.pressure_msl, ' hPa') + '\n\n';
    r += days + '-day forecast:\n';
    const d = w.daily;
    for (let i = 0; i < d.time.length; i++) {
      r += d.time[i] + ': ' + wmoText(d.weather_code[i]) + ', ' + num(d.temperature_2m_min[i]) + ' to ' + num(d.temperature_2m_max[i], '°C')
        + ', precip ' + num(d.precipitation_sum[i], ' mm');
      if (d.precipitation_probability_max[i] !== null && d.precipitation_probability_max[i] !== undefined) r += ' (' + d.precipitation_probability_max[i] + '%)';
      r += ', wind ' + num(d.wind_speed_10m_max[i], ' km/h') + ' (gusts ' + num(d.wind_gusts_10m_max[i]) + ')';
      r += ', UV ' + num(d.uv_index_max[i]) + ', sun ' + String(d.sunrise[i] || '').substring(11) + '-' + String(d.sunset[i] || '').substring(11);
      if (d.snowfall_sum[i] > 0) r += ', snow ' + d.snowfall_sum[i] + ' cm';
      r += '\n';
    }
    return out(r);
  }

  if (action === 'get_hourly_forecast') {
    if (!input.city) return fail('Parameter "city" is required (e.g. "Berlin").');
    const g = await geocode(input.city);
    let url = 'https://api.open-meteo.com/v1/forecast?latitude=' + g.lat + '&longitude=' + g.lon
      + '&hourly=temperature_2m,apparent_temperature,precipitation_probability,precipitation,weather_code,wind_speed_10m,uv_index,relative_humidity_2m,cloud_cover&timezone=auto';
    let scope;
    if (input.date) {
      if (!/^\d{4}-\d{2}-\d{2}$/.test(input.date)) return fail('Parameter "date" must be YYYY-MM-DD (e.g. "2026-07-05") and within the next 16 days.');
      url += '&start_date=' + input.date + '&end_date=' + input.date;
      scope = 'on ' + input.date;
    } else {
      let hours = parseInt(input.hours) || 24;
      hours = Math.min(Math.max(hours, 1), 48);
      url += '&forecast_hours=' + hours;
      scope = 'next ' + hours + ' hours';
    }
    let w;
    try {
      w = await helpers.httpRequest({ method: 'GET', url: url, timeout: 20000 });
    } catch (e) {
      return fail('Hourly forecast failed: ' + e.message + '. Note: "date" must be within the next 16 days (use get_weather_history for past dates).');
    }
    const h = w.hourly;
    let r = 'Hourly forecast for ' + placeLabel(g) + ' (' + scope + '):\n';
    let curDay = '';
    for (let i = 0; i < h.time.length; i++) {
      const day = h.time[i].substring(0, 10);
      const hm = h.time[i].substring(11);
      if (day !== curDay) { r += day + ':\n'; curDay = day; }
      let prob = (h.precipitation_probability[i] === null || h.precipitation_probability[i] === undefined) ? 'n/a' : h.precipitation_probability[i] + '%';
      r += '  ' + hm + ' ' + num(h.temperature_2m[i], '°C') + ' (feels ' + num(h.apparent_temperature[i]) + '), ' + wmoText(h.weather_code[i])
        + ', rain ' + prob + '/' + num(h.precipitation[i], 'mm') + ', wind ' + num(h.wind_speed_10m[i], 'km/h')
        + ', UV ' + num(h.uv_index[i]) + ', hum ' + num(h.relative_humidity_2m[i], '%') + ', cloud ' + num(h.cloud_cover[i], '%') + '\n';
    }
    return out(r);
  }

  if (action === 'get_air_quality') {
    if (!input.city) return fail('Parameter "city" is required (e.g. "Berlin").');
    const g = await geocode(input.city);
    const w = await helpers.httpRequest({
      method: 'GET', timeout: 20000,
      url: 'https://air-quality-api.open-meteo.com/v1/air-quality?latitude=' + g.lat + '&longitude=' + g.lon
        + '&current=european_aqi,us_aqi,pm10,pm2_5,ozone,nitrogen_dioxide,sulphur_dioxide,uv_index,alder_pollen,birch_pollen,grass_pollen,mugwort_pollen,olive_pollen,ragweed_pollen&timezone=auto'
    });
    const c = w.current || {};
    let r = 'Air quality for ' + placeLabel(g) + ':\n';
    if (c.european_aqi !== null && c.european_aqi !== undefined) {
      const v = c.european_aqi;
      const lvl = v <= 20 ? 'good' : v <= 40 ? 'fair' : v <= 60 ? 'moderate' : v <= 80 ? 'poor' : v <= 100 ? 'very poor' : 'extremely poor';
      r += 'European AQI: ' + v + ' (' + lvl + ')\n';
    }
    if (c.us_aqi !== null && c.us_aqi !== undefined) r += 'US AQI: ' + c.us_aqi + '\n';
    r += 'PM2.5: ' + num(c.pm2_5, ' µg/m³') + ', PM10: ' + num(c.pm10, ' µg/m³') + ', Ozone: ' + num(c.ozone, ' µg/m³')
      + ', NO2: ' + num(c.nitrogen_dioxide, ' µg/m³') + ', SO2: ' + num(c.sulphur_dioxide, ' µg/m³') + '\n';
    r += 'UV index: ' + num(c.uv_index) + '\n';
    const pollen = [['Alder', c.alder_pollen], ['Birch', c.birch_pollen], ['Grass', c.grass_pollen], ['Mugwort', c.mugwort_pollen], ['Olive', c.olive_pollen], ['Ragweed', c.ragweed_pollen]];
    const avail = pollen.filter(function (p) { return p[1] !== null && p[1] !== undefined; });
    if (avail.length > 0) {
      r += 'Pollen (grains/m³): ' + avail.map(function (p) { return p[0] + ' ' + p[1]; }).join(', ') + '\n';
    } else {
      r += 'Pollen: no data (pollen forecasts are only available in Europe)\n';
    }
    return out(r);
  }

  if (action === 'get_weather_history') {
    if (!input.city) return fail('Parameter "city" is required (e.g. "Berlin").');
    if (!input.start_date || !/^\d{4}-\d{2}-\d{2}$/.test(input.start_date) || !input.end_date || !/^\d{4}-\d{2}-\d{2}$/.test(input.end_date)) {
      return fail('Parameters "start_date" and "end_date" are required in YYYY-MM-DD format (e.g. "2025-06-01"). Data is available from 1940 onwards.');
    }
    const startMs = Date.parse(input.start_date);
    const endMs = Date.parse(input.end_date);
    if (endMs < startMs) return fail('"end_date" must not be before "start_date".');
    const rangeDays = Math.round((endMs - startMs) / 86400000) + 1;
    if (rangeDays > 31) return fail('Date range too large (' + rangeDays + ' days). Maximum is 31 days per call - split the request into smaller ranges.');
    if (endMs >= Date.now()) return fail('"end_date" must be in the past. For current or future weather use get_weather or get_hourly_forecast.');
    const g = await geocode(input.city);
    const w = await helpers.httpRequest({
      method: 'GET', timeout: 30000,
      url: 'https://archive-api.open-meteo.com/v1/archive?latitude=' + g.lat + '&longitude=' + g.lon
        + '&start_date=' + input.start_date + '&end_date=' + input.end_date
        + '&daily=weather_code,temperature_2m_max,temperature_2m_min,precipitation_sum,wind_speed_10m_max&timezone=auto'
    });
    const d = w.daily;
    if (!d || !d.time || d.time.length === 0) return fail('No historical data returned for this range.');
    let r = 'Historical weather for ' + placeLabel(g) + ' (' + input.start_date + ' to ' + input.end_date + '):\n';
    let allNull = true;
    for (let i = 0; i < d.time.length; i++) {
      if (d.temperature_2m_max[i] !== null && d.temperature_2m_max[i] !== undefined) allNull = false;
      r += d.time[i] + ': ' + wmoText(d.weather_code[i]) + ', ' + num(d.temperature_2m_min[i]) + ' to ' + num(d.temperature_2m_max[i], '°C')
        + ', precip ' + num(d.precipitation_sum[i], ' mm') + ', wind ' + num(d.wind_speed_10m_max[i], ' km/h') + '\n';
    }
    if (allNull) return fail('No data for this range yet. The weather archive lags about 5 days behind - for the last few days use get_weather instead.');
    return out(r);
  }

  if (action === 'get_marine_weather') {
    if (!input.city) return fail('Parameter "city" is required (a coastal location, e.g. "Kiel", "Nice").');
    const g = await geocode(input.city);
    let days = parseInt(input.days) || 3;
    days = Math.min(Math.max(days, 1), 7);
    let w;
    try {
      w = await helpers.httpRequest({
        method: 'GET', timeout: 20000,
        url: 'https://marine-api.open-meteo.com/v1/marine?latitude=' + g.lat + '&longitude=' + g.lon
          + '&current=wave_height,wave_direction,wave_period,sea_surface_temperature'
          + '&daily=wave_height_max,wave_direction_dominant,wave_period_max&timezone=auto&forecast_days=' + days
      });
    } catch (e) {
      return fail('No marine data available for "' + g.name + '". This tool needs a coastal or offshore location (e.g. "Kiel", "Palma de Mallorca").');
    }
    const c = w.current || {};
    if ((c.wave_height === null || c.wave_height === undefined) && (c.sea_surface_temperature === null || c.sea_surface_temperature === undefined)) {
      return fail('No marine data available for "' + g.name + '" - it seems to be too far inland. Try a coastal location (e.g. "Kiel", "Palma de Mallorca").');
    }
    let r = 'Marine conditions near ' + placeLabel(g) + '\n';
    r += 'Now: waves ' + num(c.wave_height, ' m') + ' from ' + num(c.wave_direction, '°') + ', period ' + num(c.wave_period, ' s')
      + ', sea surface temp ' + num(c.sea_surface_temperature, '°C') + '\n\n';
    const d = w.daily;
    if (d && d.time) {
      r += days + '-day wave forecast:\n';
      for (let i = 0; i < d.time.length; i++) {
        r += d.time[i] + ': max waves ' + num(d.wave_height_max[i], ' m') + ' from ' + num(d.wave_direction_dominant[i], '°') + ', max period ' + num(d.wave_period_max[i], ' s') + '\n';
      }
    }
    return out(r);
  }

  if (action === 'get_weather_alerts') {
    if (!input.city) return fail('Parameter "city" is required (e.g. "Berlin", "Vienna").');
    const g = await geocode(input.city);

    if (g.cc === 'DE') {
      const b = await helpers.httpRequest({ method: 'GET', timeout: 20000, url: 'https://api.brightsky.dev/alerts?lat=' + g.lat + '&lon=' + g.lon });
      const loc = b.location || {};
      const where = g.name + (loc.district ? ' (' + loc.district + ', ' + (loc.state || '') + ')' : '');
      const active = (b.alerts || []).filter(function (a) { return notExpired(a.expires); });
      if (active.length === 0) {
        return out('No active weather alerts for ' + where + '. Source: DWD. Note: advance notices for events several days ahead may not be listed yet.');
      }
      let r = 'Active weather alerts for ' + where + ' (source: DWD, times in UTC):\n\n';
      const list = active.slice(0, 5);
      for (const a of list) {
        r += '[' + (a.severity || 'unknown').toUpperCase() + '] ' + (a.event_en || a.event_de || a.headline_en || 'Alert') + '\n';
        r += '  ' + tfmt(a.onset) + ' to ' + tfmt(a.expires) + '\n';
        let desc = a.description_en || a.description_de || '';
        if (desc.length > 300) desc = desc.substring(0, 300) + '...';
        if (desc) r += '  ' + desc.replace(/\n+/g, ' ') + '\n';
        r += '\n';
      }
      if (active.length > 5) r += '(' + (active.length - 5) + ' more alerts not shown)\n';
      return out(r);
    }

    if (g.cc === 'CH') {
      const xml = await helpers.httpRequest({ method: 'GET', timeout: 30000, url: 'https://feeds.meteoalarm.org/feeds/meteoalarm-legacy-atom-switzerland' });
      const xs = String(xml);
      const entries = xs.split('<entry>').slice(1);
      const cands = areaCandidates(input.city, g);
      const items = [];
      for (const en of entries) {
        const gx = function (tag) {
          const m = en.match(new RegExp('<' + tag + '[^>]*>([\\s\\S]*?)</' + tag + '>'));
          return m ? m[1].trim() : '';
        };
        const it = { area: gx('cap:areaDesc'), event: gx('cap:event') || gx('title'), severity: gx('cap:severity'), onset: gx('cap:onset') || gx('cap:effective'), expires: gx('cap:expires') };
        if (notExpired(it.expires)) items.push(it);
      }
      const hits = items.filter(function (it) {
        const al = norm(it.area);
        return cands.some(function (c) { return al.includes(c); });
      }).sort(function (x, y) {
        const sx = SEV_ORDER[x.severity.toLowerCase()]; const sy = SEV_ORDER[y.severity.toLowerCase()];
        return (sx === undefined ? 9 : sx) - (sy === undefined ? 9 : sy);
      });
      if (hits.length === 0) {
        return out('No active weather alerts matching "' + g.name + '". Switzerland currently has ' + items.length + ' active alert(s) in other regions. Source: MeteoAlarm/MeteoSwiss.');
      }
      let r = 'Active weather alerts for ' + placeLabel(g) + ' (source: MeteoAlarm/MeteoSwiss):\n\n';
      for (const it of hits.slice(0, 5)) {
        r += '[' + (it.severity || 'unknown').toUpperCase() + '] ' + it.event + ' - ' + it.area + '\n';
        r += '  ' + tfmt(it.onset) + ' to ' + tfmt(it.expires) + '\n\n';
      }
      if (hits.length > 5) r += '(' + (hits.length - 5) + ' more alerts not shown)\n';
      return out(r);
    }

    const feed = MA_FEEDS[g.cc];
    if (!feed) {
      return out('Weather alerts are only available for Europe (MeteoAlarm) and Germany (DWD). No alert source for ' + (g.country || g.cc) + '. Tip: get_weather shows wind gusts, precipitation and UV, which often indicate severe conditions.');
    }
    const data = await helpers.httpRequest({ method: 'GET', timeout: 30000, url: 'https://feeds.meteoalarm.org/api/v1/warnings/feeds-' + feed });
    const warnings = data.warnings || [];
    if (warnings.length === 0) {
      return out('No active weather alerts for ' + (g.country || g.cc) + '. Source: MeteoAlarm.');
    }
    const cands = areaCandidates(input.city, g);
    const items = [];
    for (const wr of warnings) {
      const alert = wr.alert;
      if (!alert || !alert.info || alert.info.length === 0) continue;
      let info = null;
      for (const inf of alert.info) {
        if (String(inf.language || '').toLowerCase().indexOf('en') === 0) { info = inf; break; }
      }
      if (!info) info = alert.info[0];
      if (!notExpired(info.expires)) continue;
      const areas = [];
      for (const ar of (info.area || [])) { if (ar.areaDesc) areas.push(ar.areaDesc); }
      const matched = areas.filter(function (ad) {
        const adl = norm(ad);
        return cands.some(function (c) { return adl.includes(c); });
      });
      items.push({
        matched: matched, areas: areas,
        event: info.event || info.headline || 'Alert',
        severity: String(info.severity || ''),
        onset: info.onset || info.effective || '', expires: info.expires || '',
        desc: String(info.description || '')
      });
    }
    const bySeverity = function (x, y) {
      const sx = SEV_ORDER[x.severity.toLowerCase()]; const sy = SEV_ORDER[y.severity.toLowerCase()];
      return (sx === undefined ? 9 : sx) - (sy === undefined ? 9 : sy);
    };
    const hits = items.filter(function (it) { return it.matched.length > 0; }).sort(bySeverity);
    if (hits.length === 0) {
      if (items.length === 0) return out('No active weather alerts for ' + (g.country || g.cc) + '. Source: MeteoAlarm.');
      const counts = {};
      for (const it of items) { const s = it.severity || 'Unknown'; counts[s] = (counts[s] || 0) + 1; }
      const parts = [];
      for (const k in counts) parts.push(counts[k] + ' ' + k);
      let r = 'No active weather alerts matching "' + g.name + '". ' + (g.country || g.cc) + ' currently has ' + items.length + ' active alert(s) in other regions (' + parts.join(', ') + '). Source: MeteoAlarm.\nMost severe elsewhere:\n';
      const top = items.slice().sort(bySeverity).slice(0, 3);
      for (const it of top) r += '- [' + it.severity.toUpperCase() + '] ' + it.event + ' - ' + (it.areas[0] || '') + (it.areas.length > 1 ? ' (+' + (it.areas.length - 1) + ' areas)' : '') + '\n';
      return out(r);
    }
    let r = 'Active weather alerts for ' + placeLabel(g) + ' (source: MeteoAlarm):\n\n';
    for (const it of hits.slice(0, 5)) {
      r += '[' + (it.severity || 'unknown').toUpperCase() + '] ' + it.event + ' - ' + it.matched.slice(0, 3).join('; ') + '\n';
      r += '  ' + tfmt(it.onset) + ' to ' + tfmt(it.expires) + '\n';
      let desc = it.desc;
      if (desc.length > 250) desc = desc.substring(0, 250) + '...';
      if (desc) r += '  ' + desc.replace(/\n+/g, ' ') + '\n';
      r += '\n';
    }
    if (hits.length > 5) r += '(' + (hits.length - 5) + ' more alerts not shown)\n';
    return out(r);
  }

  return fail('Unknown action: "' + action + '". Available: get_weather, get_hourly_forecast, get_air_quality, get_weather_history, get_marine_weather, get_weather_alerts.');
} catch (e) {
  return fail(e.message);
}
